import { Link, animateScroll as scroll } from "react-scroll";
import styled from "styled-components";
import Brand from "./Brand";
import hamburger from '../../img/LandingPage/hamburger.svg'

const Nav = ( props ) => {
  return (
    <NavContainer fixed={props.fixed}>
      <Link to="/">
        <Brand />
      </Link>
      <img src={hamburger} alt="show categories" />
      {/* <ul>
        <li> */}
          <Link to="About" smooth={true} duration={500}>
            About
          </Link>
        {/* </li>
      </ul> */}
    </NavContainer>
  )
}

const NavContainer = styled.nav`
  grid-column: 1/3;
  display: flex;
  justify-content: space-between;
  padding: 2em;

  position: sticky;

  & img {
    filter: invert(1);
    width: 2em;
    height: 2em;
  }
`

export default Nav
